import { useNavigate } from "react-router-dom";
import { FrstImageInfo, FrstInfoImage } from "../../components/ImageInfo";

function Service1() {
    const navigate = useNavigate();
    const handleRouting = (route, pageName) => {
        navigate(route, { state: pageName ? { pageName: pageName, imageSrc: "beautiful-beach-using-young-happy.jpg" } : null });
    };

    return (
        <>
            <section >
                <div className='container pt-5'>
                    <div className='row'>
                        <div className='col-md-6 my-5 text-end pe-5'>
                            <h1 className="p-0 m-0">Creative</h1>
                            <h5 className="p-0 m-0">Opportunities</h5>
                        </div>
                        <div className='col-md-6 my-5'>
                            <p>Our services are designed to support both emerging and professional models while connecting them with brands, designers, and creative teams. From portfolio development and fashion campaigns to casting opportunities and promotional events, we focus on creating meaningful opportunities in the fashion industry. Our team works closely with talent and clients to ensure every collaboration is professional, creative, and aligned with modern industry standards.</p>
                        </div>
                    </div>
                </div>
            </section >
            <section>
                <FrstImageInfo handleRouting={handleRouting} />
                <FrstInfoImage handleRouting={handleRouting} />
            </section>
        </>
    )
}

export default Service1;